function lRUCache(data) {
    const text = (data || '').trim();
    if (!text) return '0';

    const lines = text.split(/\n/);
    const capacity = parseInt((lines[0] || '').trim(), 10);
    if (!Number.isFinite(capacity) || capacity <= 0) return '0';

    const tokens = lines.slice(1).join(' ').trim().split(/\s+/).filter(Boolean);
    const cache = new Map();
    const out = [];

    const touch = (key, value) => {
        if (cache.has(key)) cache.delete(key);
        cache.set(key, value);
        if (cache.size > capacity) {
            const oldest = cache.keys().next().value;
            cache.delete(oldest);
        }
    };

    let i = 0;
    while (i < tokens.length) {
        const op = tokens[i++];
        if (op === 'put' && i + 1 < tokens.length) {
            const k = parseInt(tokens[i++], 10);
            const v = parseInt(tokens[i++], 10);
            touch(k, v);
        } else if (op === 'get' && i < tokens.length) {
            const k = parseInt(tokens[i++], 10);
            if (cache.has(k)) {
                const v = cache.get(k);
                touch(k, v);
                out.push(String(v));
            } else {
                out.push('-1');
            }
        }
    }

    return out.length ? out.join(' ') : '0';
}

